    const requiredSet = new Set(required.map((entry) => entry.id));
    const rest = (selectedEntries || [])
      .filter((entry) => !requiredSet.has(entry.id))
      .map((entry) => ({ ...entry, required: false }));
    return [...required, ...rest];
